//! Launch Interceptor Program (Knight & Leveson, 1986) — DECIDE procedure.

pub const PI: f64 = 3.1415926535;

pub const LT: &str = "LT";
pub const EQ: &str = "EQ";
pub const GT: &str = "GT";

pub fn realcompare(a: f64, b: f64) -> &'static str {
    let scale = a.abs().max(b.abs());
    if scale == 0.0 {
        return EQ;
    }
    let eps = 0.5e-5 * scale;
    let diff = a - b;
    if diff > eps {
        GT
    } else if diff < -eps {
        LT
    } else {
        EQ
    }
}

fn rc_lt(a: f64, b: f64) -> bool {
    realcompare(a, b) == LT
}
fn rc_gt(a: f64, b: f64) -> bool {
    realcompare(a, b) == GT
}
fn rc_eq(a: f64, b: f64) -> bool {
    realcompare(a, b) == EQ
}
fn rc_le(a: f64, b: f64) -> bool {
    !rc_gt(a, b)
}

#[derive(Clone, Debug)]
pub struct Parameters {
    pub length1: f64,
    pub radius1: f64,
    pub epsilon: f64,
    pub area1: f64,
    pub q_pts: usize,
    pub quads: usize,
    pub dist: f64,
    pub n_pts: usize,
    pub k_pts: usize,
    pub a_pts: usize,
    pub b_pts: usize,
    pub c_pts: usize,
    pub d_pts: usize,
    pub e_pts: usize,
    pub f_pts: usize,
    pub g_pts: usize,
    pub length2: f64,
    pub radius2: f64,
    pub area2: f64,
}

#[derive(Clone, Copy, PartialEq, Eq)]
pub enum Connector {
    NotUsed,
    Orr,
    Andd,
}

pub struct DecideInput {
    pub numpoints: usize,
    pub x: Vec<f64>,
    pub y: Vec<f64>,
    pub parameters: Parameters,
    pub lcm: [[Connector; 15]; 15],
    pub pum_diag: [bool; 15],
}

pub struct DecideOutput {
    pub cmv: [bool; 15],
    pub pum: [[bool; 15]; 15],
    pub fuv: [bool; 15],
    pub launch: bool,
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    (dx * dx + dy * dy).sqrt()
}

fn points_equal(x: &[f64], y: &[f64], i: usize, j: usize) -> bool {
    rc_eq(x[i], x[j]) && rc_eq(y[i], y[j])
}

fn triangle_area(x: &[f64], y: &[f64], i: usize, j: usize, k: usize) -> f64 {
    let area2 = (x[j] - x[i]) * (y[k] - y[i]) - (x[k] - x[i]) * (y[j] - y[i]);
    0.5 * area2.abs()
}

/// Minimum radius of a circle that contains three points (on or inside).
fn min_enclosing_radius(x: &[f64], y: &[f64], i: usize, j: usize, k: usize) -> f64 {
    let d12 = dist(x[i], y[i], x[j], y[j]);
    let d23 = dist(x[j], y[j], x[k], y[k]);
    let d13 = dist(x[i], y[i], x[k], y[k]);
    let max_pair = d12.max(d23).max(d13);

    let area = triangle_area(x, y, i, j, k);
    if rc_eq(area, 0.0) {
        return max_pair / 2.0;
    }

    let circum = (d12 * d23 * d13) / (4.0 * area);
    if rc_gt(circum, max_pair / 2.0) {
        circum
    } else {
        max_pair / 2.0
    }
}

fn fits_in_circle(x: &[f64], y: &[f64], i: usize, j: usize, k: usize, radius: f64) -> bool {
    rc_le(min_enclosing_radius(x, y, i, j, k), radius)
}

fn angle_at_vertex(x: &[f64], y: &[f64], a: usize, b: usize, c: usize) -> Option<f64> {
    if points_equal(x, y, a, b) || points_equal(x, y, c, b) {
        return None;
    }
    let v1x = x[a] - x[b];
    let v1y = y[a] - y[b];
    let v2x = x[c] - x[b];
    let v2y = y[c] - y[b];
    let len1 = (v1x * v1x + v1y * v1y).sqrt();
    let len2 = (v2x * v2x + v2y * v2y).sqrt();
    if rc_eq(len1, 0.0) || rc_eq(len2, 0.0) {
        return None;
    }
    let mut cos_theta = (v1x * v2x + v1y * v2y) / (len1 * len2);
    if rc_gt(cos_theta, 1.0) {
        cos_theta = 1.0;
    } else if rc_lt(cos_theta, -1.0) {
        cos_theta = -1.0;
    }
    Some(cos_theta.acos())
}

fn lic3_angle_met(x: &[f64], y: &[f64], a: usize, b: usize, c: usize, epsilon: f64) -> bool {
    match angle_at_vertex(x, y, a, b, c) {
        None => false,
        Some(angle) => rc_lt(angle, PI - epsilon) || rc_gt(angle, PI + epsilon),
    }
}

/// Quadrant I=1 .. IV=4 per spec axis-priority rules.
fn quadrant(x: f64, y: f64) -> u8 {
    if rc_eq(x, 0.0) && rc_eq(y, 0.0) {
        return 1;
    }
    if rc_lt(x, 0.0) && rc_eq(y, 0.0) {
        return 2;
    }
    if rc_eq(x, 0.0) && rc_lt(y, 0.0) {
        return 3;
    }
    if rc_eq(x, 0.0) && rc_gt(y, 0.0) {
        return 1;
    }
    if rc_gt(x, 0.0) && rc_eq(y, 0.0) {
        return 1;
    }
    if rc_gt(x, 0.0) && rc_gt(y, 0.0) {
        return 1;
    }
    if rc_lt(x, 0.0) && rc_gt(y, 0.0) {
        return 2;
    }
    if rc_lt(x, 0.0) && rc_lt(y, 0.0) {
        return 3;
    }
    if rc_gt(x, 0.0) && rc_lt(y, 0.0) {
        return 4;
    }
    // Remaining axis/ambiguous cases: negative x with y != 0 already handled
    if rc_lt(x, 0.0) {
        return 2;
    }
    1
}

fn point_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let len_sq = dx * dx + dy * dy;
    if rc_eq(len_sq, 0.0) {
        return dist(px, py, x1, y1);
    }
    let num = ((py - y1) * dx - (px - x1) * dy).abs();
    num / len_sq.sqrt()
}

fn lic1(x: &[f64], y: &[f64], n: usize, length1: f64) -> bool {
    for i in 0..n - 1 {
        if rc_gt(dist(x[i], y[i], x[i + 1], y[i + 1]), length1) {
            return true;
        }
    }
    false
}

fn lic2(x: &[f64], y: &[f64], n: usize, radius1: f64) -> bool {
    for i in 0..n.saturating_sub(2) {
        if !fits_in_circle(x, y, i, i + 1, i + 2, radius1) {
            return true;
        }
    }
    false
}

fn lic3(x: &[f64], y: &[f64], n: usize, epsilon: f64) -> bool {
    for i in 0..n.saturating_sub(2) {
        if lic3_angle_met(x, y, i, i + 1, i + 2, epsilon) {
            return true;
        }
    }
    false
}

fn lic4(x: &[f64], y: &[f64], n: usize, area1: f64) -> bool {
    for i in 0..n.saturating_sub(2) {
        if rc_gt(triangle_area(x, y, i, i + 1, i + 2), area1) {
            return true;
        }
    }
    false
}

fn lic5(x: &[f64], y: &[f64], n: usize, q_pts: usize, quads: usize) -> bool {
    if q_pts > n {
        return false;
    }
    for start in 0..=n - q_pts {
        let mut seen = [false; 5];
        let mut count = 0usize;
        for i in start..start + q_pts {
            let q = quadrant(x[i], y[i]) as usize;
            if !seen[q] {
                seen[q] = true;
                count += 1;
            }
        }
        if count > quads {
            return true;
        }
    }
    false
}

fn lic6(x: &[f64], _y: &[f64], n: usize) -> bool {
    for i in 0..n - 1 {
        if rc_lt(x[i + 1], x[i]) {
            return true;
        }
    }
    false
}

fn lic7(x: &[f64], y: &[f64], n: usize, n_pts: usize, dist_limit: f64) -> bool {
    if n < 3 {
        return false;
    }
    for start in 0..=n - n_pts {
        let end = start + n_pts - 1;
        let x1 = x[start];
        let y1 = y[start];
        let x2 = x[end];
        let y2 = y[end];
        let coincident = rc_eq(x1, x2) && rc_eq(y1, y2);
        for i in start..=end {
            let d = if coincident {
                if i == start {
                    continue;
                }
                dist(x[i], y[i], x1, y1)
            } else {
                point_line_distance(x[i], y[i], x1, y1, x2, y2)
            };
            if rc_gt(d, dist_limit) {
                return true;
            }
        }
    }
    false
}

fn lic8(x: &[f64], y: &[f64], n: usize, k_pts: usize, length1: f64) -> bool {
    if n < 3 {
        return false;
    }
    for i in 0..n - k_pts - 1 {
        let j = i + k_pts + 1;
        if rc_gt(dist(x[i], y[i], x[j], y[j]), length1) {
            return true;
        }
    }
    false
}

fn lic9(x: &[f64], y: &[f64], n: usize, a_pts: usize, b_pts: usize, radius1: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = a_pts + b_pts + 2;
    if n <= span {
        return false;
    }
    for i in 0..n - span {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if !fits_in_circle(x, y, i, j, k, radius1) {
            return true;
        }
    }
    false
}

fn lic10(x: &[f64], y: &[f64], n: usize, c_pts: usize, d_pts: usize, epsilon: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = c_pts + d_pts + 2;
    if n <= span {
        return false;
    }
    for i in 0..n - span {
        let j = i + c_pts + 1;
        let k = i + c_pts + d_pts + 2;
        if lic3_angle_met(x, y, i, j, k, epsilon) {
            return true;
        }
    }
    false
}

fn lic11(x: &[f64], y: &[f64], n: usize, e_pts: usize, f_pts: usize, area1: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = e_pts + f_pts + 2;
    if n <= span {
        return false;
    }
    for i in 0..n - span {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        if rc_gt(triangle_area(x, y, i, j, k), area1) {
            return true;
        }
    }
    false
}

fn lic12(x: &[f64], _y: &[f64], n: usize, g_pts: usize) -> bool {
    if n < 3 {
        return false;
    }
    for i in 0..n - g_pts - 1 {
        let j = i + g_pts + 1;
        if rc_lt(x[j], x[i]) {
            return true;
        }
    }
    false
}

fn lic13(x: &[f64], y: &[f64], n: usize, k_pts: usize, length1: f64, length2: f64) -> bool {
    if n < 3 {
        return false;
    }
    let mut has_gt = false;
    let mut has_lt = false;
    for i in 0..n - k_pts - 1 {
        let j = i + k_pts + 1;
        let d = dist(x[i], y[i], x[j], y[j]);
        if rc_gt(d, length1) {
            has_gt = true;
        }
        if rc_lt(d, length2) {
            has_lt = true;
        }
        if has_gt && has_lt {
            return true;
        }
    }
    false
}

fn lic14(x: &[f64], y: &[f64], n: usize, a_pts: usize, b_pts: usize, radius1: f64, radius2: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = a_pts + b_pts + 2;
    if n <= span {
        return false;
    }
    let mut not_in_r1 = false;
    let mut in_r2 = false;
    for i in 0..n - span {
        let j = i + a_pts + 1;
        let k = i + a_pts + b_pts + 2;
        if !fits_in_circle(x, y, i, j, k, radius1) {
            not_in_r1 = true;
        }
        if fits_in_circle(x, y, i, j, k, radius2) {
            in_r2 = true;
        }
        if not_in_r1 && in_r2 {
            return true;
        }
    }
    false
}

fn lic15(x: &[f64], y: &[f64], n: usize, e_pts: usize, f_pts: usize, area1: f64, area2: f64) -> bool {
    if n < 5 {
        return false;
    }
    let span = e_pts + f_pts + 2;
    if n <= span {
        return false;
    }
    let mut gt_area1 = false;
    let mut lt_area2 = false;
    for i in 0..n - span {
        let j = i + e_pts + 1;
        let k = i + e_pts + f_pts + 2;
        let area = triangle_area(x, y, i, j, k);
        if rc_gt(area, area1) {
            gt_area1 = true;
        }
        if rc_lt(area, area2) {
            lt_area2 = true;
        }
        if gt_area1 && lt_area2 {
            return true;
        }
    }
    false
}

pub fn compute_cmv(input: &DecideInput) -> [bool; 15] {
    let n = input.numpoints;
    let x = &input.x;
    let y = &input.y;
    let p = &input.parameters;

    [
        lic1(x, y, n, p.length1),
        lic2(x, y, n, p.radius1),
        lic3(x, y, n, p.epsilon),
        lic4(x, y, n, p.area1),
        lic5(x, y, n, p.q_pts, p.quads),
        lic6(x, y, n),
        lic7(x, y, n, p.n_pts, p.dist),
        lic8(x, y, n, p.k_pts, p.length1),
        lic9(x, y, n, p.a_pts, p.b_pts, p.radius1),
        lic10(x, y, n, p.c_pts, p.d_pts, p.epsilon),
        lic11(x, y, n, p.e_pts, p.f_pts, p.area1),
        lic12(x, y, n, p.g_pts),
        lic13(x, y, n, p.k_pts, p.length1, p.length2),
        lic14(x, y, n, p.a_pts, p.b_pts, p.radius1, p.radius2),
        lic15(x, y, n, p.e_pts, p.f_pts, p.area1, p.area2),
    ]
}

fn apply_lcm(cmv: &[bool; 15], lcm: &[[Connector; 15]; 15]) -> [[bool; 15]; 15] {
    let mut off = [[false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                continue;
            }
            off[i][j] = match lcm[i][j] {
                Connector::NotUsed => true,
                Connector::Andd => cmv[i] && cmv[j],
                Connector::Orr => cmv[i] || cmv[j],
            };
        }
    }
    off
}

pub fn compute_fuv(pum: &[[bool; 15]; 15]) -> [bool; 15] {
    let mut fuv = [false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = (0..15).all(|j| pum[i][j]);
        }
    }
    fuv
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let cmv = compute_cmv(input);
    let off = apply_lcm(&cmv, &input.lcm);
    let mut pum = [[false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                pum[i][j] = off[i][j];
            }
        }
    }
    let fuv = compute_fuv(&pum);
    let launch = fuv.iter().all(|&v| v);
    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
